ox = ra*sin(sp);
oy = sin(sample*3.14-1.57)*rad;
oz = ra*cos(sp);

xang = tm*.132;
sxang = 0;
yang = tm*.153;
ayang = 0;
zang = tm*.110;
azang = 0;
fov = 0.6 + 0.2*sin(tm);
